import{_ as e,c as t,o as r,d as a}from"./app.bfb02d77.js";const u='{"title":"\u0420\u0438\u0442\u043C \u0440\u0430\u0431\u043E\u0442\u044B \u043E\u0442\u043A\u0440\u044B\u0442\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439","description":"","frontmatter":{"title":"\u0420\u0438\u0442\u043C \u0440\u0430\u0431\u043E\u0442\u044B \u043E\u0442\u043A\u0440\u044B\u0442\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439","subtitle":"\u0420\u0430\u0441\u043F\u043E\u0440\u044F\u0434\u043E\u043A \u0440\u0430\u0431\u043E\u0442\u044B \u0432 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u043C \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435","date":"2015-08-14","cover":"time-3.png"},"headers":[{"level":3,"title":"\u0421\u0435\u0441\u0441\u0438\u0438 \u043F\u043E \u0442\u0440\u0438\xA0\u0447\u0430\u0441\u0430","slug":"\u0441\u0435\u0441\u0441\u0438\u0438-\u043F\u043E-\u0442\u0440\u0438-\u0447\u0430\u0441\u0430"},{"level":3,"title":"\u041F\u0440\u0438\u043C\u0435\u0440 \u0440\u0430\u0441\u043F\u0438\u0441\u0430\u043D\u0438\u044F \u0434\u043D\u044F \u0441 \u0443\u0447\u0435\u0442\u043E\u043C \u0442\u0440\u0451\u0445\u0447\u0430\u0441\u043E\u0432\u044B\u0445 \u0441\u0435\u0441\u0441\u0438\u0439","slug":"\u043F\u0440\u0438\u043C\u0435\u0440-\u0440\u0430\u0441\u043F\u0438\u0441\u0430\u043D\u0438\u044F-\u0434\u043D\u044F-\u0441-\u0443\u0447\u0435\u0442\u043E\u043C-\u0442\u0440\u0451\u0445\u0447\u0430\u0441\u043E\u0432\u044B\u0445-\u0441\u0435\u0441\u0441\u0438\u0439"}],"relativePath":"theory/system/rhythm/index.md"}',n={},s=a('<p>\u041C\u043E\u0436\u043D\u043E \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u0438\u0442\u044C \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F \u043B\u044E\u0434\u0435\u0439 \u0432 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \u043A\u0430\u043A \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u044F \u0432 \u0435\u0434\u0438\u043D\u043E\u043C \u0441\u043B\u043E\u0436\u043D\u043E\u043C \u0442\u0430\u043D\u0446\u0435, \u0430 \u0448\u0443\u043C \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432 \u043A\u0430\u043A \u0437\u0432\u0443\u043A\u0438 \u043C\u0443\u0437\u044B\u043A\u0438 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0430. \u0412\u0441\u0451 \u0436\u0438\u0432\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0432 \u043A\u0430\u043A\u043E\u043C-\u0442\u043E \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u043E\u043C \u0440\u0438\u0442\u043C\u0435. \u0418 \u043D\u0430\u043C \u0443\u0434\u0430\u043B\u043E\u0441\u044C \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0438\u0442\u044C \u0441\u0443\u0442\u043E\u0447\u043D\u044B\u0439 \u0440\u0438\u0442\u043C \u043E\u0442\u043A\u0440\u044B\u0442\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439.</p><h3 id="\u0441\u0435\u0441\u0441\u0438\u0438-\u043F\u043E-\u0442\u0440\u0438-\u0447\u0430\u0441\u0430" tabindex="-1">\u0421\u0435\u0441\u0441\u0438\u0438 \u043F\u043E \u0442\u0440\u0438\xA0\u0447\u0430\u0441\u0430 <a class="header-anchor" href="#\u0441\u0435\u0441\u0441\u0438\u0438-\u043F\u043E-\u0442\u0440\u0438-\u0447\u0430\u0441\u0430" aria-hidden="true">#</a></h3><p>\u0421\u0435\u0441\u0441\u0438\u0438 \u043D\u0430\u0447\u0438\u043D\u0430\u044E\u0442\u0441\u044F \u043F\u043E \u0440\u0430\u0441\u043F\u0438\u0441\u0430\u043D\u0438\u044E \u0438\u043B\u0438 \u043F\u043E \u0444\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u0438. \u041D\u0430 \u043A\u0430\u0436\u0434\u0443\u044E \u043E\u0442\u043A\u0440\u044B\u0442\u0443\u044E \u0441\u0435\u0441\u0441\u0438\u044E \u0444\u043E\u0440\u043C\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u0433\u0440\u0443\u043F\u043F\u0430 \u0443\u0447\u0430\u0441\u0442\u043D\u0438\u043A\u043E\u0432, \u0441\u043E\u0432\u043C\u0435\u0441\u0442\u043D\u043E \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0445 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0443\u044E \u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u0441\u043E\u0433\u043B\u0430\u0441\u043E\u0432\u0430\u043D\u043D\u043E \u0432 \u0442\u0435\u0447\u0435\u043D\u0438\u0435 \u0442\u0440\u0451\u0445 \u0447\u0430\u0441\u043E\u0432. \u041C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F \u0434\u043E\u043B\u0436\u043D\u0430 \u0431\u044B\u0442\u044C \u0447\u0438\u0441\u0442\u0430 \u0438 \u0433\u043E\u0442\u043E\u0432\u0430 \u043A \u0440\u0430\u0431\u043E\u0442\u0435 \u043A\u0430\u043A \u0432 \u043D\u0430\u0447\u0430\u043B\u0435, \u0442\u0430\u043A \u0438 \u0432 \u043A\u043E\u043D\u0446\u0435 \u043E\u0442\u043A\u0440\u044B\u0442\u043E\u0439 \u0441\u0435\u0441\u0441\u0438\u0438. \u041F\u0435\u0440\u0432\u044B\u0435 \u043F\u043E\u043B\u0447\u0430\u0441\u0430 \u2014 \u043F\u043E\u0434\u0433\u043E\u0442\u043E\u0432\u043A\u0430 \u0438 \u0438\u043D\u0441\u0442\u0440\u0443\u043A\u0446\u0438\u0438. \u0417\u0430\u0442\u0435\u043C \u0434\u0432\u0430 \u0447\u0430\u0441\u0430 \u0438\u043D\u0442\u0435\u043D\u0441\u0438\u0432\u043D\u043E\u0439 \u0440\u0430\u0431\u043E\u0442\u044B. \u041A\u043E\u043B\u043B\u0435\u043A\u0442\u0438\u0432\u043D\u0430\u044F \u0443\u0431\u043E\u0440\u043A\u0430 \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F \u0437\u0430 \u043F\u043E\u043B\u0447\u0430\u0441\u0430 \u0434\u043E \u0437\u0430\u0432\u0435\u0440\u0448\u0435\u043D\u0438\u044F \u0441\u0435\u0441\u0441\u0438\u0438. \u041F\u043E \u0437\u0430\u0432\u0435\u0440\u0448\u0435\u043D\u0438\u044E \u2014 \u043A\u0440\u0430\u0442\u043A\u0438\u0439 \u043E\u0431\u0437\u043E\u0440 \u0441\u0435\u0441\u0441\u0438\u0438 \u0438 \u043E\u0431\u0441\u0443\u0436\u0434\u0435\u043D\u0438\u0435 \u0435\u0451 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u043E\u0432.</p><p>\u041F\u043E\u0447\u0435\u043C\u0443 \u0442\u0440\u0438\xA0\u0447\u0430\u0441\u0430? \u042D\u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043E\u043F\u0442\u0438\u043C\u0430\u043B\u044C\u043D\u043E \u043A\u0430\u043A \u0441 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u0435\u0439 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430 \u043A \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u0438, \u0442\u0430\u043A \u0438 \u0441 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0441\u0442\u0438 \u0438 \u043F\u0440\u0435\u0434\u0441\u043A\u0430\u0437\u0443\u0435\u043C\u043E\u0441\u0442\u0438 \u0440\u0430\u0431\u043E\u0442\u044B \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439.\xA0\u0412 DIY-\u0410\u043A\u0430\u0434\u0435\u043C\u0438\u0438 \u0440\u0430\u0431\u043E\u0442\u0430 \u0442\u0430\u0440\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u0442\u0430\u043A\u0438\u043C\u0438 \u043E\u0442\u0440\u0435\u0437\u043A\u0430\u043C\u0438, \u0430 \u0432 \u0412\u0435\u043B\u043E\u043A\u0443\u0445\u043D\u044F\u0445 \u043F\u043E \u0432\u0441\u0435\u043C\u0443 \u043C\u0438\u0440\u0443 \u0438\u043C\u0435\u043D\u043D\u043E \u0441\u0442\u043E\u043B\u044C\u043A\u043E \u0434\u043B\u044F\u0442\u0441\u044F \u043E\u0442\u043A\u0440\u044B\u0442\u044B\u0435 \u0447\u0430\u0441\u044B.</p><h4 id="\u043E\u0434\u0438\u043D-\u0447\u0430\u0441-\u043F\u0435\u0440\u0435\u0440\u044B\u0432" tabindex="-1">\u041E\u0434\u0438\u043D \u0447\u0430\u0441 \u043F\u0435\u0440\u0435\u0440\u044B\u0432 <a class="header-anchor" href="#\u043E\u0434\u0438\u043D-\u0447\u0430\u0441-\u043F\u0435\u0440\u0435\u0440\u044B\u0432" aria-hidden="true">#</a></h4><p>\u041D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435 \u043C\u043E\u0436\u0435\u0442 \u0440\u0430\u0431\u043E\u0442\u0430\u0442\u044C \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E \u0432 \u0442\u0435\u0447\u0435\u043D\u0438\u0435 \u0437\u043D\u0430\u0447\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0438, \u0430 \u043B\u044E\u0434\u0438, \u0441\u0438\u043B\u044C\u043D\u043E \u0443\u0432\u043B\u0451\u043A\u0448\u0438\u0441\u044C, \u043C\u043E\u0433\u0443\u0442 \u0442\u0440\u0443\u0434\u0438\u0442\u044C\u0441\u044F\xA0\u0441\u0443\u0442\u043A\u0430\u043C\u0438, \u043F\u0435\u0440\u0435\u0440\u044B\u0432\u044B \u0432\u0430\u0436\u043D\u044B \u0434\u043B\u044F \u0432\u0441\u0435\u0445. \u0412\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u043F\u0435\u0440\u0435\u043A\u043B\u044E\u0447\u0438\u0442\u044C\u0441\u044F, \u043E\u0442\u0434\u043E\u0445\u043D\u0443\u0442\u044C, \u043F\u0435\u0440\u0435\u043A\u0443\u0441\u0438\u0442\u044C, \u043F\u043E\u043E\u0431\u0449\u0430\u0442\u044C\u0441\u044F, \u043F\u043E\u0434\u0433\u043E\u0442\u043E\u0432\u0438\u0442\u044C\u0441\u044F \u043A \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0439 \u0441\u0435\u0441\u0441\u0438\u0438. \u042D\u0442\u043E \u0432\u0440\u0435\u043C\u044F \u0442\u0430\u043A\u0436\u0435 \u0432\u0430\u0436\u043D\u043E \u0434\u043B\u044F \u0441\u043C\u0435\u043D\u044B \u0432\u043E\u043B\u043E\u043D\u0442\u0451\u0440\u0441\u043A\u0438\u0445 \u043A\u043E\u043C\u0430\u043D\u0434 \u0438 \u043C\u043D\u043E\u0433\u0438\u0445 \u0434\u0440\u0443\u0433\u0438\u0445 \u0437\u0430\u0434\u0430\u0447 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439.</p><h4 id="\u0434\u043E-\u0442\u0440\u0451\u0445-\u0441\u0435\u0441\u0441\u0438\u0439-\u0432-\u0434\u0435\u043D\u044C-\u043F\u043E-\u0440\u0430\u0441\u043F\u0438\u0441\u0430\u043D\u0438\u044E" tabindex="-1">\u0414\u043E \u0442\u0440\u0451\u0445 \u0441\u0435\u0441\u0441\u0438\u0439 \u0432 \u0434\u0435\u043D\u044C \u043F\u043E \u0440\u0430\u0441\u043F\u0438\u0441\u0430\u043D\u0438\u044E <a class="header-anchor" href="#\u0434\u043E-\u0442\u0440\u0451\u0445-\u0441\u0435\u0441\u0441\u0438\u0439-\u0432-\u0434\u0435\u043D\u044C-\u043F\u043E-\u0440\u0430\u0441\u043F\u0438\u0441\u0430\u043D\u0438\u044E" aria-hidden="true">#</a></h4><p>\u0420\u0430\u0431\u043E\u0442\u0430 \u0432 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \u043A\u0430\u043A \u043F\u0440\u0430\u0432\u0438\u043B\u043E \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u0431\u043B\u0430\u0433\u043E\u043F\u0440\u0438\u044F\u0442\u043D\u0430 \u043F\u0440\u0438 \u0441\u043E\u043B\u043D\u0435\u0447\u043D\u043E\u043C \u043E\u0441\u0432\u0435\u0449\u0435\u043D\u0438\u0438 \u0438 \u0432 \u0431\u043E\u0434\u0440\u043E\u043C \u0438 \u0440\u0430\u0441\u0441\u043B\u0430\u0431\u043B\u0435\u043D\u043D\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438.\xA0\u0422\u0440\u0438 \u043E\u0442\u043A\u0440\u044B\u0442\u044B\u0445 \u0441\u0435\u0441\u0441\u0438\u0438 \u0441 \u0434\u0432\u0443\u043C\u044F \u043F\u0435\u0440\u0435\u0440\u044B\u0432\u0430\u043C\u0438 \u043C\u0435\u0436\u0434\u0443 \u043D\u0438\u043C\u0438 \u2014 \u044D\u0442\u043E <strong>\u043E\u0434\u0438\u043D\u043D\u0430\u0434\u0446\u0430\u0442\u044C\xA0\u0447\u0430\u0441\u043E\u0432</strong>, \u043F\u043E\u0447\u0442\u0438 \u043F\u043E\u043B\u043E\u0432\u0438\u043D\u0430 \u0441\u0443\u0442\u043E\u043A. \u041E\u0441\u0442\u0430\u0432\u0438\u043C \u043D\u043E\u0447\u044C \u0434\u043B\u044F \u0441\u043D\u0430, \u043E\u0442\u0432\u0435\u0434\u0451\u043C \u0432\u0440\u0435\u043C\u044F \u043D\u0430 \u0434\u043E\u0440\u043E\u0433\u0443 \u0438 \u043B\u0438\u0447\u043D\u044B\u0435 \u043D\u0443\u0436\u0434\u044B \u0438 \u043F\u043E\u0439\u043C\u0451\u043C, \u0447\u0442\u043E \u044D\u0442\u043E\u0433\u043E \u0443\u0436\u0435 \u0432\u043F\u043E\u043B\u043D\u0435 \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u0434\u043B\u044F \u043F\u0440\u043E\u0434\u0443\u043A\u0442\u0438\u0432\u043D\u043E\u0433\u043E \u0434\u043D\u044F. \u041A\u043E\u043D\u0435\u0447\u043D\u043E, \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0438\u043C \u043D\u0435 \u043E\u0431\u044F\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u043F\u0440\u043E\u0432\u043E\u0434\u0438\u0442\u044C \u0432\u0441\u0435 \u0442\u0440\u0438 \u0441\u0435\u0441\u0441\u0438\u0438 \u0432 \u043E\u0442\u043A\u0440\u044B\u0442\u043E\u043C \u0440\u0435\u0436\u0438\u043C\u0435 \u043A\u0430\u0436\u0434\u044B\u0439 \u0434\u0435\u043D\u044C. \u0412\u0430\u0436\u043D\u043E \u0441\u0442\u0440\u0435\u043C\u0438\u0442\u044C\u0441\u044F \u043A \u044D\u0442\u043E\u043C\u0443, \u043D\u043E \u0441\u0442\u043E\u0438\u0442 \u0431\u044B\u0442\u044C \u0440\u0435\u0430\u043B\u0438\u0441\u0442\u0438\u0447\u043D\u044B\u043C\u0438 \u0432 \u043E\u0446\u0435\u043D\u043A\u0435\xA0\u0434\u043E\u0431\u0440\u043E\u0432\u043E\u043B\u044C\u0447\u0435\u0441\u043A\u0438\u0445 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u0435\u0439. \u041C\u043E\u0441\u043A\u043E\u0432\u0441\u043A\u0430\u044F \u0412\u0435\u043B\u043E\u043A\u0443\u0445\u043D\u044F, \u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442 \u0441\u0432\u043E\u0439 \u043F\u0443\u0442\u044C <strong>\u0441 \u043E\u0434\u043D\u043E\u0439 \u043E\u0442\u043A\u0440\u044B\u0442\u043E\u0439 \u0441\u0435\u0441\u0441\u0438\u0438 \u0432 \u043D\u0435\u0434\u0435\u043B\u044E</strong> \u043F\u043E \u043F\u043E\u043D\u0435\u0434\u0435\u043B\u044C\u043D\u0438\u043A\u0430\u043C \u0441 18 \u0434\u043E 21 \u0447\u0430\u0441\u0430.</p><h4 id="\u0441\u0435\u0441\u0441\u0438\u0438-\u0431\u044B\u0432\u0430\u044E\u0442-\u0440\u0430\u0437\u043D\u044B\u0435" tabindex="-1">\u0421\u0435\u0441\u0441\u0438\u0438 \u0431\u044B\u0432\u0430\u044E\u0442 \u0440\u0430\u0437\u043D\u044B\u0435 <a class="header-anchor" href="#\u0441\u0435\u0441\u0441\u0438\u0438-\u0431\u044B\u0432\u0430\u044E\u0442-\u0440\u0430\u0437\u043D\u044B\u0435" aria-hidden="true">#</a></h4><p>\u041F\u043E\u043C\u0438\u043C\u043E\xA0\u0440\u0430\u0431\u043E\u0447\u0438\u0445 \u0441\u0435\u0441\u0441\u0438\u0439 \u0432 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \u043C\u043E\u0433\u0443\u0442 \u043F\u0440\u043E\u0432\u043E\u0434\u0438\u0442\u044C\u0441\u044F \u0432\u0441\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u0435 <strong>\u043A\u043B\u0430\u0441\u0441\u044B \u0438 \u043A\u0443\u0440\u0441\u044B, \u043F\u043E\u043A\u0430\u0437\u044B-\u0440\u0430\u0441\u0441\u043A\u0430\u0437\u044B, \u0432\u044B\u0441\u0442\u0430\u0432\u043A\u0438-\u043F\u0440\u043E\u0434\u0430\u0436\u0438</strong> \u0438 \u0442\u0435\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435 <strong>\u0432\u0441\u0442\u0440\u0435\u0447\u0438 \u0438 \u0431\u0435\u0441\u0435\u0434\u044B</strong> \u0437\u0430\u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043E\u0432\u0430\u043D\u043D\u044B\u0445 \u043B\u0438\u0446. \u0412 \u044D\u0442\u043E\u043C \u0436\u0435 \u0440\u0438\u0442\u043C\u0435 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F \u043C\u043E\u0436\u0435\u0442 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u0438 \u0432 \u0437\u0430\u043A\u0440\u044B\u0442\u043E\u043C \u0440\u0435\u0436\u0438\u043C\u0435 <strong>\u0442\u043E\u043B\u044C\u043A\u043E \u043C\u0430\u0441\u0442\u0435\u0440\u0430\u043C\u0438</strong>, \xA0\u0430 \u0434\u043B\u044F \u043F\u0440\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044F \u043F\u043E\u043B\u043D\u043E\u0446\u0435\u043D\u043D\u043E\u0439 \u043E\u0442\u043A\u0440\u044B\u0442\u043E\u0439 \u0441\u0435\u0441\u0441\u0438\u0438 \u043F\u043E\u0442\u0440\u0435\u0431\u0443\u0435\u0442\u0441\u044F \u043F\u043E\u0434\u0433\u043E\u0442\u043E\u0432\u043B\u0435\u043D\u043D\u0430\u044F \u043A\u043E\u043C\u0430\u043D\u0434\u0430 \u0432\u043E\u043B\u043E\u043D\u0442\u0451\u0440\u043E\u0432, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0430\u044F \u0445\u043E\u0442\u044F \u0431\u044B <strong>\u0438\u0437 \u043E\u0434\u043D\u043E\u0433\u043E \u0430\u0434\u043C\u0438\u043D\u0438\u0441\u0442\u0440\u0430\u0442\u043E\u0440\u0430 \u0438 \u043E\u0434\u043D\u043E\u0433\u043E \u043A\u0443\u0440\u0430\u0442\u043E\u0440\u0430</strong>. \u0410\u0434\u043C\u0438\u043D\u0438\u0441\u0442\u0440\u0430\u0442\u043E\u0440 \u043E\u0431\u0435\u0441\u043F\u0435\u0447\u0438\u0442 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0430\u043C\u0438, \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u0430\u043C\u0438 \u0438 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E\u043C, \u043A\u0443\u0440\u0430\u0442\u043E\u0440 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0442 \u043D\u0430\u0447\u0438\u043D\u0430\u043D\u0438\u044F <strong>\u0443\u043C\u0435\u043B\u044C\u0446\u0435\u0432</strong> \u0438 \u0443\u0442\u043E\u043B\u0438\u0442 \u0438\u043D\u0442\u0435\u0440\u0435\u0441 <strong>\u0433\u043E\u0441\u0442\u0435\u0439</strong>.</p><h3 id="\u043F\u0440\u0438\u043C\u0435\u0440-\u0440\u0430\u0441\u043F\u0438\u0441\u0430\u043D\u0438\u044F-\u0434\u043D\u044F-\u0441-\u0443\u0447\u0435\u0442\u043E\u043C-\u0442\u0440\u0451\u0445\u0447\u0430\u0441\u043E\u0432\u044B\u0445-\u0441\u0435\u0441\u0441\u0438\u0439" tabindex="-1">\u041F\u0440\u0438\u043C\u0435\u0440 \u0440\u0430\u0441\u043F\u0438\u0441\u0430\u043D\u0438\u044F \u0434\u043D\u044F \u0441 \u0443\u0447\u0435\u0442\u043E\u043C \u0442\u0440\u0451\u0445\u0447\u0430\u0441\u043E\u0432\u044B\u0445 \u0441\u0435\u0441\u0441\u0438\u0439 <a class="header-anchor" href="#\u043F\u0440\u0438\u043C\u0435\u0440-\u0440\u0430\u0441\u043F\u0438\u0441\u0430\u043D\u0438\u044F-\u0434\u043D\u044F-\u0441-\u0443\u0447\u0435\u0442\u043E\u043C-\u0442\u0440\u0451\u0445\u0447\u0430\u0441\u043E\u0432\u044B\u0445-\u0441\u0435\u0441\u0441\u0438\u0439" aria-hidden="true">#</a></h3><p><strong>\u041E\u0442\u043A\u0440\u044B\u0442\u043E: 10:00\u201413:00, \xA014:00\u201417:00, 18:00\u201421:00</strong> <strong>\u041F\u0435\u0440\u0435\u0440\u044B\u0432: 13:00\u201414:00, 17:00\u201418:00</strong></p>',12),o=[s];function d(i,h,c,_,p,g){return r(),t("div",null,o)}var f=e(n,[["render",d]]);export{u as __pageData,f as default};
